        # Convert SearchResult to dictionary format
        result_dict = _convert_searchresult_to_dict(result)
        results_as_dicts.append(result_dict)
        result_mapping[idx] = result

    # Initialize the MetadataFilterEngine
    filter_engine = MetadataFilterEngine()

    # Apply filters based on the specified logic
    if filter_logic.upper() == "AND":
        # Apply all filters with AND logic
        filtered_indices = set(range(len(results_as_dicts)))

        for field_name, conditions in filter_specs.items():
            for operator, value in conditions.items():
                current_filtered = set()

                for idx, result_dict in enumerate(results_as_dicts):
                    if _evaluate_condition(result_dict, field_name, operator, value):
                        current_filtered.add(idx)

                # Intersect with existing filtered indices for AND logic
                filtered_indices = filtered_indices.intersection(current_filtered)

                # Early termination if no results match
                if not filtered_indices:
                    break

            if not filtered_indices:
                break

    elif filter_logic.upper() == "OR":
        # Apply filters with OR logic
        filtered_indices = set()

        for field_name, conditions in filter_specs.items():
            for operator, value in conditions.items():
                for idx, result_dict in enumerate(results_as_dicts):
                    if _evaluate_condition(result_dict, field_name, operator, value):
                        filtered_indices.add(idx)

    else:
        raise ValueError(f"Unsupported filter logic: {filter_logic}. Use 'AND' or 'OR'.")

    # Convert filtered indices back to SearchResult objects
    filtered_results = []
    for idx in sorted(filtered_indices):
        filtered_results.append(result_mapping[idx])

    return filtered_results


def _convert_searchresult_to_dict(result: SearchResult) -> Dict[str, Any]:
    """Convert a SearchResult object to a dictionary for filtering operations."""
    # Assuming SearchResult has a to_dict() method or accessible attributes
    if hasattr(result, 'to_dict') and callable(getattr(result, 'to_dict')):
        return result.to_dict()
    else:
        # Fallback: convert object attributes to dictionary
        return {attr: getattr(result, attr) for attr in dir(result) 
                if not attr.startswith('_') and not callable(getattr(result, attr))}


