    if field_name not in result_dict:
        return False

    field_value = result_dict[field_name]

    try:
        if operator == "==":
            return field_value == value
        elif operator == "!=":
            return field_value != value
        elif operator == ">":
            return field_value > value
        elif operator == ">=":
            return field_value >= value
        elif operator == "<":
            return field_value < value
        elif operator == "<=":
            return field_value <= value
        elif operator == "in":
            return field_value in value
        elif operator == "not in":
            return field_value not in value
        elif operator == "contains":
            return value in field_value
        elif operator == "startswith":
            return field_value.startswith(value)
        elif operator == "endswith":
            return field_value.endswith(value)
        else:
            # Use MetadataFilterEngine for complex or custom operators
            filter_engine = MetadataFilterEngine()
            condition_spec = {field_name: {operator: value}}
